/*! Local offline ECharts-compatible runtime for this dashboard.
 *  It implements the small ECharts API surface used by financial_dcf_dashboard.html:
 *  echarts.init(el).setOption(option), resize(), and dispose().
 */
(function(global){
  function fmt(v){
    var n=Number(v||0),a=Math.abs(n);
    if(a>=1e8)return (n/1e8).toFixed(2)+" \u4ebf";
    if(a>=1e4)return (n/1e4).toFixed(2)+" \u4e07";
    return n.toLocaleString("zh-CN",{maximumFractionDigits:2});
  }
  function colorAt(opt,i){
    var c=opt.color||["#2563eb","#10b981","#f97316","#7c3aed","#0f766e"];
    return c[i%c.length];
  }
  function makeCanvas(el){
    el.innerHTML="";
    el.style.position="relative";
    var canvas=document.createElement("canvas");
    canvas.style.width="100%";
    canvas.style.height="100%";
    canvas.style.display="block";
    el.appendChild(canvas);
    var tip=document.createElement("div");
    tip.style.cssText="position:absolute;pointer-events:none;display:none;background:rgba(15,23,42,.92);color:#fff;border-radius:6px;padding:8px 10px;font:12px Segoe UI,Arial,sans-serif;box-shadow:0 8px 24px rgba(0,0,0,.18);z-index:3;white-space:nowrap";
    el.appendChild(tip);
    return {canvas:canvas,tip:tip};
  }
  function Chart(el){
    this.el=el;
    var parts=makeCanvas(el);
    this.canvas=parts.canvas;
    this.tip=parts.tip;
    this.option=null;
    var self=this;
    this.canvas.addEventListener("mousemove",function(e){self.move(e);});
    this.canvas.addEventListener("mouseleave",function(){self.tip.style.display="none";});
  }
  Chart.prototype.setOption=function(option){
    this.option=option||{};
    this.draw();
  };
  Chart.prototype.resize=function(){this.draw();};
  Chart.prototype.dispose=function(){this.el.innerHTML="";};
  Chart.prototype.metrics=function(){
    var canvas=this.canvas,rect=this.el.getBoundingClientRect(),dpr=window.devicePixelRatio||1;
    canvas.width=Math.max(320,Math.floor(rect.width*dpr));
    canvas.height=Math.max(260,Math.floor(rect.height*dpr));
    var ctx=canvas.getContext("2d");
    ctx.setTransform(dpr,0,0,dpr,0,0);
    var grid=(this.option&&this.option.grid)||{};
    return {ctx:ctx,w:canvas.width/dpr,h:canvas.height/dpr,left:grid.left||70,right:grid.right||24,top:grid.top||42,bottom:grid.bottom||42};
  };
  Chart.prototype.bounds=function(series,axisIndex){
    var vals=[];
    series.forEach(function(s){
      if(Number(s.yAxisIndex||0)!==axisIndex)return;
      (s.data||[]).forEach(function(v){vals.push(Number(v)||0);});
    });
    vals.push(0);
    var min=Math.min.apply(null,vals),max=Math.max.apply(null,vals);
    if(Math.abs(max-min)<1e-9){max=min+1;}
    var pad=(max-min)*0.08;
    return {min:min-pad,max:max+pad};
  };
  Chart.prototype.draw=function(){
    if(!this.option)return;
    var m=this.metrics(),ctx=m.ctx,w=m.w,h=m.h,opt=this.option;
    ctx.clearRect(0,0,w,h);
    ctx.font="12px Segoe UI,Arial,sans-serif";
    ctx.textBaseline="middle";
    var labels=(opt.xAxis&&opt.xAxis.data)||[];
    var series=opt.series||[];
    var axisCount=Array.isArray(opt.yAxis)?opt.yAxis.length:1;
    var bounds=[];
    for(var ai=0;ai<Math.max(1,axisCount);ai++)bounds[ai]=this.bounds(series,ai);
    var pw=w-m.left-m.right,ph=h-m.top-m.bottom;
    var band=function(i){return m.left+(i+.5)*pw/Math.max(1,labels.length);};
    var x=band;
    var y=function(v,axisIndex){var b=bounds[axisIndex||0]||bounds[0];return m.top+(b.max-v)*(ph/(b.max-b.min));};
    ctx.strokeStyle="#e8edf5";ctx.lineWidth=1;
    ctx.fillStyle="#687385";
    for(var g=0;g<5;g++){
      var gy=m.top+g*ph/4;
      ctx.beginPath();ctx.moveTo(m.left,gy);ctx.lineTo(w-m.right,gy);ctx.stroke();
      var b0=bounds[0],val=b0.max-g*(b0.max-b0.min)/4;
      ctx.textAlign="right";ctx.fillText(fmt(val),m.left-8,gy);
      if(axisCount>1){
        var b1=bounds[1],val1=b1.max-g*(b1.max-b1.min)/4;
        ctx.textAlign="left";ctx.fillText(fmt(val1),w-m.right+8,gy);
      }
    }
    ctx.strokeStyle="#9aa6b8";
    ctx.beginPath();ctx.moveTo(m.left,h-m.bottom);ctx.lineTo(w-m.right,h-m.bottom);ctx.stroke();
    ctx.textAlign="center";
    labels.forEach(function(lbl,i){ctx.fillText(String(lbl),labels.length>1?x(i):band(i),h-18);});
    var legendX=m.left;
    series.forEach(function(s,si){
      var c=colorAt(opt,si);
      ctx.fillStyle=c;ctx.fillRect(legendX,m.top-30,10,10);
      ctx.fillStyle="#687385";ctx.textAlign="left";ctx.fillText(s.name||("Series "+(si+1)),legendX+15,m.top-25);
      legendX+=ctx.measureText(s.name||"Series").width+70;
    });
    var drawOrder=series.map(function(s,si){return {s:s,si:si};}).sort(function(a,b){
      var az=a.s.type==="bar"?0:1,bz=b.s.type==="bar"?0:1;
      return az-bz;
    });
    drawOrder.forEach(function(item){
      var s=item.s,si=item.si;
      var data=(s.data||[]).map(function(v){return Number(v)||0;}),c=colorAt(opt,si),axisIndex=Number(s.yAxisIndex||0);
      if(s.type==="bar"){
        var bw=Math.min(s.barMaxWidth||42,pw/Math.max(1,labels.length)*.58);
        data.forEach(function(v,i){
          var cx=band(i),yy=y(Math.max(v,0),axisIndex),zy=y(0,axisIndex),hh=Math.abs(zy-y(v,axisIndex));
          ctx.fillStyle=c;
          ctx.beginPath();
          var rx=cx-bw/2, ry=v>=0?yy:zy;
          ctx.rect(rx,ry,bw,Math.max(1,hh));
          ctx.fill();
        });
      }else{
        ctx.strokeStyle=c;ctx.lineWidth=3;ctx.beginPath();
        data.forEach(function(v,i){var xx=x(i),yy=y(v,axisIndex);if(i===0)ctx.moveTo(xx,yy);else ctx.lineTo(xx,yy);});
        ctx.stroke();
        data.forEach(function(v,i){ctx.fillStyle=c;ctx.beginPath();ctx.arc(x(i),y(v,axisIndex),3.5,0,Math.PI*2);ctx.fill();});
      }
    });
    this._points=labels.map(function(lbl,i){return {x:labels.length>1?x(i):band(i),label:lbl,index:i};});
  };
  Chart.prototype.move=function(e){
    if(!this._points||!this.option)return;
    var rect=this.canvas.getBoundingClientRect(),mx=e.clientX-rect.left,best=null,dist=1e9;
    this._points.forEach(function(p){var d=Math.abs(p.x-mx);if(d<dist){dist=d;best=p;}});
    if(!best||dist>36){this.tip.style.display="none";return;}
    var html="<strong>"+best.label+"</strong>";
    (this.option.series||[]).forEach(function(s,si){
      var v=(s.data||[])[best.index];
      html+="<br><span style='color:"+colorAt(this.option,si)+"'>●</span> "+(s.name||"Series")+": "+fmt(v);
    },this);
    this.tip.innerHTML=html;
    this.tip.style.display="block";
    this.tip.style.left=Math.min(rect.width-180,Math.max(4,best.x+10))+"px";
    this.tip.style.top="48px";
  };
  global.echarts={init:function(el){return new Chart(el);},version:"local-offline-dashboard"};
})(window);
